1	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
2	type Damage = { itemType: string; amount: number };
3	type Incident = { cause: string; damages: Damage[] };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type QuoteResult = { premium: number };
8	type ClaimResult = { payout: number };
9	type Result = QuoteResult | ClaimResult;
10	type Customer = { yearsWithMHPCO: number };
11	type ScenarioInput = { customer: Customer; steps: Step[] };
12	type ScenarioOutput = { results: Result[] };
