102	const claimPayout = (step: ClaimStep, policyItems: Item[]): number => {
103	  const gross = step.incident.damages.reduce(
104	    (sum, damage) => sum + damageReimbursement(damage, policyItems),
105	    0,
106	  );
107	  return Math.max(0, gross - DEDUCTIBLE);
108	};
