110	const runStep = (
111	  step: Step,
112	  customer: Customer,
113	  isFirstQuote: boolean,
114	  policiesItems: (Item[] | undefined)[],
115	): Result =>
116	  step.op === "claim"
117	    ? { payout: claimPayout(step, policiesItems[step.policy] ?? []) }
118	    : { premium: quotePremium(step.items, customer.yearsWithMHPCO, isFirstQuote) };
119	
120	export const runScenario = (input: ScenarioInput): ScenarioOutput => {
121	  const policiesItems = input.steps.map((step) =>
122	    step.op === "quote" ? step.items : undefined,
123	  );
124	  return {
125	    results: input.steps.map((step, index) =>
126	      runStep(step, input.customer, index === 0, policiesItems),
127	    ),
128	  };
129	};
